import { Link } from 'react-router-dom'
import { useState } from "react";

function Header() {
    const [openHmFlag, setHOpen] = useState(false);
    const [openSrvFlag, setSOpen] = useState(false);

    const srvMenuList = [
        {
            "id": 1,
            "serviceName": "Model Management",
            "route": null,
            "imgSrc": "young-happy-woman-porch-stairs.jpg"
        },
        {
            "id": 2,
            "serviceName": "Portfolio Development",
            "route": null,
            "imgSrc": "young-happy-woman-porch-stairs.jpg"
        },
        {
            "id": 3,
            "serviceName": "Fashion & Brand Campaigns",
            "route": null,
            "imgSrc": "young-happy-woman-porch-stairs.jpg"
        },
        {
            "id": 4,
            "serviceName": "Runway & Fashion Shows",
            "route": null,
            "imgSrc": "young-happy-woman-porch-stairs.jpg"
        },
        {
            "id": 5,
            "serviceName": "Casting & Auditions",
            "route": null,
            "imgSrc": "young-happy-woman-porch-stairs.jpg"
        },
        {
            "id": 6,
            "serviceName": "Commercial & Advertisement Shoots",
            "route": null,
            "imgSrc": "young-happy-woman-porch-stairs.jpg"
        },
        {
            "id": 7,
            "serviceName": "Influencer & Social Media Promotion",
            "route": null,
            "imgSrc": "young-happy-woman-porch-stairs.jpg"
        },
        {
            "id": 8,
            "serviceName": "Event Modeling",
            "route": null,
            "imgSrc": "young-happy-woman-porch-stairs.jpg"
        }
    ]

    return (
        <header className="navbar navbar-expand-lg position-absolute w-100 pt-0" >
            <div className="container-fluid">
                <Link className="navbar-brand" to="/">
                    <h5 className='cls-color-wht'>CMe</h5>
                </Link>

                <button
                    className="navbar-toggler cls-color-wht"
                    type="button"
                    data-bs-toggle="collapse"
                    data-bs-target="#navbarNav"
                >
                    <span className="fa-solid fa-bars cls-color-wht"></span>
                </button>

                <div className="collapse navbar-collapse justify-content-end" id="navbarNav">
                    <ul className="navbar-nav">

                        <li className="nav-item cls-services-parent" onMouseLeave={() => setHOpen(!openHmFlag)}>
                            <span className="nav-link cls-text-sml cls-color-wht mb-2" onMouseEnter={() => { setSOpen(false); setHOpen(!openHmFlag) }}>Home</span>
                            {openHmFlag && (
                                <ul className='cls-service-submenu' >
                                    <li className="nav-item">
                                        <Link className="nav-link cls-text-sml cls-color-wht mb-2" to="/">Main Home 1</Link>
                                    </li>
                                    <li className="nav-item">
                                        <Link className="nav-link cls-text-sml cls-color-wht mb-2" to="/home1">Main Home 2</Link>
                                    </li>
                                </ul>
                            )}
                        </li>

                        <li className="nav-item cls-services-parent" onMouseLeave={() => setSOpen(!openSrvFlag)}>
                            <span className="nav-link cls-text-sml cls-color-wht mb-2" onMouseEnter={() => { setHOpen(false); setSOpen(!openSrvFlag) }}>Services</span>
                            {openSrvFlag && (
                                <ul className='cls-service-submenu' >
                                    {
                                        srvMenuList.map((srvmnu) => (
                                            <li className="nav-item" key={srvmnu.id}>
                                                <Link className="nav-link cls-text-sml cls-color-wht mb-2" to="/service/service1" state={{ parent: "Service", pageName: srvmnu.serviceName, imageSrc: srvmnu.imgSrc }}>{srvmnu.serviceName}</Link>
                                            </li>
                                        ))
                                    }

                                </ul>
                            )}
                        </li>

                        <li className="nav-item">
                            <Link className="nav-link cls-text-sml cls-color-wht mb-2" to="/works" state={{ pageName: "Works", imageSrc: "photographer-checking-his-camera-darkness.jpg" }}>Works</Link>
                        </li>

                        <li className="nav-item">
                            <Link className="nav-link cls-text-sml cls-color-wht mb-2" to="/blog" state={{ pageName: "Blog", imageSrc: "woman-using-binoculars-forest.jpg" }}>Blog</Link>
                        </li>

                        <li className="nav-item">
                            <Link className="nav-link cls-text-sml cls-color-wht mb-2" to="/team" state={{ pageName: "Team", imageSrc: "artists-doing-touch-ups-model.jpg" }}>Team</Link>
                        </li>

                        <li className="nav-item">
                            <Link className="nav-link cls-text-sml cls-color-wht mb-2" to="/about" state={{ pageName: "About", imageSrc: "back-view-woman-taking-mirror-photos.jpg" }}>About</Link>
                        </li>

                        <li className="nav-item">
                            <Link className="nav-link cls-text-sml cls-color-wht mb-2" to="/contact" state={{ pageName: "Contact", imageSrc: "beautiful-beach-using-young-happy.jpg" }}>Contact</Link>
                        </li>
                    </ul>
                </div>
            </div >
        </header >
    )
}

export default Header;